import React, { useEffect, useState } from 'react';
import { Expand, Minimize2 } from 'lucide-react';

const formatCurrency = (value) =>
  new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2 }).format(Number(value || 0));

const STORAGE_KEY = 'khmart_pos_cart';
const ABA_QR_IMAGE_SOURCES = ['/images/aba-qr.png', '/images/aba-qr.jpg', '/images/aba-qr.jpeg', '/images/aba-qr.webp'];

const readCartData = () => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      return {
        currentOrder: null,
        lastCompletedSale: null,
        viewMode: 'idle',
        thanksUntil: null,
        thankYouMessage: 'Thank you for shopping at KH Mart!',
      };
    }

    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== 'object') {
      return {
        currentOrder: null,
        lastCompletedSale: null,
        viewMode: 'idle',
        thanksUntil: null,
        thankYouMessage: 'Thank you for shopping at KH Mart!',
      };
    }

    // Backward compatibility for older payload shape.
    if (Array.isArray(parsed.cart)) {
      return {
        currentOrder: {
          cart: parsed.cart,
          subtotal: Number(parsed.subtotal || 0),
          discountAmount: Number(parsed.discountAmount || 0),
          grandTotal: Number(parsed.grandTotal || 0),
          appliedDiscount: parsed.appliedDiscount || null,
          paymentMethod: parsed.paymentMethod || 'Cash',
        },
        lastCompletedSale: parsed.lastCompletedSale || null,
        viewMode: parsed.viewMode || (Array.isArray(parsed.cart) && parsed.cart.length > 0 ? 'active' : 'idle'),
        thanksUntil: parsed.thanksUntil || null,
        thankYouMessage: parsed.thankYouMessage || 'Thank you for shopping at KH Mart!',
      };
    }

    return {
      currentOrder: parsed.currentOrder || null,
      lastCompletedSale: parsed.lastCompletedSale || null,
      viewMode: parsed.viewMode || ((Array.isArray(parsed.currentOrder?.cart) && parsed.currentOrder.cart.length > 0) ? 'active' : 'idle'),
      thanksUntil: parsed.thanksUntil || null,
      thankYouMessage: parsed.thankYouMessage || 'Thank you for shopping at KH Mart!',
    };
  } catch {
    return {
      currentOrder: null,
      lastCompletedSale: null,
      viewMode: 'idle',
      thanksUntil: null,
      thankYouMessage: 'Thank you for shopping at KH Mart!',
    };
  }
};

const writeCartData = (updater) => {
  const current = readCartData();
  const next = typeof updater === 'function'
    ? updater(current)
    : { ...current, ...updater };

  localStorage.setItem(
    STORAGE_KEY,
    JSON.stringify({
      ...next,
      updatedAt: new Date().toISOString(),
    }),
  );
};

const CustomerDisplay = () => {
  const [posData, setPosData] = useState(() => readCartData());
  const [now, setNow] = useState(new Date());
  const [abaQrSourceIndex, setAbaQrSourceIndex] = useState(0);
  const [isFullscreen, setIsFullscreen] = useState(false);

  useEffect(() => {
    const clockId = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(clockId);
  }, []);

  useEffect(() => {
    const onFullscreenChange = () => {
      setIsFullscreen(Boolean(document.fullscreenElement));
    };

    document.addEventListener('fullscreenchange', onFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', onFullscreenChange);
  }, []);

  useEffect(() => {
    const handleStorage = (e) => {
      if (e.key === STORAGE_KEY) {
        setPosData(readCartData());
      }
    };
    window.addEventListener('storage', handleStorage);
    // Poll every 500ms for same-tab updates (storage event only fires across tabs)
    const pollId = setInterval(() => setPosData(readCartData()), 500);
    return () => {
      window.removeEventListener('storage', handleStorage);
      clearInterval(pollId);
    };
  }, []);

  const activeOrder = posData?.currentOrder || null;
  const completedSale = posData?.lastCompletedSale || null;
  const viewMode = posData?.viewMode || (Array.isArray(activeOrder?.cart) && activeOrder.cart.length > 0 ? 'active' : 'idle');
  const thankYouMessage = posData?.thankYouMessage || 'Thank you for shopping at KH Mart!';

  const cart = activeOrder?.cart ?? [];
  const subtotal = Number(activeOrder?.subtotal ?? 0);
  const discountAmount = Number(activeOrder?.discountAmount ?? 0);
  const grandTotal = Number(activeOrder?.grandTotal ?? 0);
  const appliedDiscount = activeOrder?.appliedDiscount ?? null;
  const activePaymentMethod = activeOrder?.paymentMethod || 'Cash';
  const activeCustomerName = String(activeOrder?.customerName || '').trim() || 'Walk-in';
  const hasItems = cart.length > 0;
  const showActiveOrder = viewMode === 'active' && hasItems;
  const showCompletedSale = viewMode === 'thanks' && Boolean(completedSale);

  const completedCart = completedSale?.cart ?? [];
  const completedSubtotal = Number(completedSale?.subtotal ?? 0);
  const completedDiscountAmount = Number(completedSale?.discountAmount ?? 0);
  const completedGrandTotal = Number(completedSale?.grandTotal ?? 0);
  const completedAppliedDiscount = completedSale?.appliedDiscount ?? null;
  const completedPaymentMethod = completedSale?.paymentMethod || 'Cash';
  const completedCustomerName = String(completedSale?.customerName || '').trim() || 'Walk-in';
  const isAbaPayment = String(completedPaymentMethod).trim().toUpperCase() === 'ABA';
  const isActiveAbaPayment = String(activePaymentMethod).trim().toUpperCase() === 'ABA';

  useEffect(() => {
    if (viewMode !== 'thanks') {
      return undefined;
    }

    const thanksUntilMs = posData?.thanksUntil ? new Date(posData.thanksUntil).getTime() : 0;

    if (!Number.isFinite(thanksUntilMs) || thanksUntilMs <= Date.now()) {
      writeCartData((current) => ({
        ...current,
        viewMode: 'idle',
        thanksUntil: null,
      }));
      setPosData(readCartData());
      return undefined;
    }

    const remainingMs = Math.max(0, thanksUntilMs - Date.now());
    const timer = setTimeout(() => {
      writeCartData((current) => ({
        ...current,
        viewMode: 'idle',
        thanksUntil: null,
      }));
      setPosData(readCartData());
    }, remainingMs);

    return () => clearTimeout(timer);
  }, [viewMode, posData?.thanksUntil]);

  useEffect(() => {
    // Reset source attempts when ABA mode is toggled off.
    if (!isAbaPayment && !isActiveAbaPayment) {
      setAbaQrSourceIndex(0);
    }
  }, [isAbaPayment, isActiveAbaPayment]);

  const abaQrImageSrc = ABA_QR_IMAGE_SOURCES[Math.min(abaQrSourceIndex, ABA_QR_IMAGE_SOURCES.length - 1)];
  const abaQrLoadError = abaQrSourceIndex >= ABA_QR_IMAGE_SOURCES.length;

  const handleAbaQrImageError = () => {
    setAbaQrSourceIndex((current) => {
      if (current >= ABA_QR_IMAGE_SOURCES.length) {
        return current;
      }
      return current + 1;
    });
  };

  const toggleFullscreen = async () => {
    try {
      if (!document.fullscreenElement) {
        await document.documentElement.requestFullscreen();
      } else {
        await document.exitFullscreen();
      }
    } catch {
      // Ignore fullscreen request errors (browser policy, user gesture, etc.)
    }
  };

  const goToStaffPage = () => {
    window.location.href = '/staff/pos';
  };

  return (
    <div className="min-h-screen flex flex-col bg-gradient-to-br from-slate-900 via-slate-800 to-emerald-950 text-white">
      {/* Header */}
      <header className="sticky top-0 z-10 flex items-center justify-between px-8 py-5 border-b border-white/10 bg-black/30 backdrop-blur shrink-0">
        <div>
          <h1 className="text-3xl font-black tracking-tight">KH Mart</h1>
          <p className="text-sm text-emerald-300 mt-0.5">Customer Display</p>
        </div>
        <div className="flex items-center gap-4">
          <button
            type="button"
            onClick={goToStaffPage}
            className="inline-flex items-center gap-2 rounded-lg border border-sky-300/30 bg-sky-500/10 px-3 py-2 text-sm font-semibold text-sky-100 transition hover:bg-sky-500/20"
          >
            Staff Page
          </button>

          <button
            type="button"
            onClick={toggleFullscreen}
            className="inline-flex items-center gap-2 rounded-lg border border-emerald-300/30 bg-emerald-400/10 px-3 py-2 text-sm font-semibold text-emerald-100 transition hover:bg-emerald-400/20"
          >
            {isFullscreen ? <Minimize2 className="w-4 h-4" /> : <Expand className="w-4 h-4" />}
            {isFullscreen ? 'Exit Fullscreen' : 'Fullscreen'}
          </button>

          <div className="text-right">
            <p className="text-2xl font-bold tabular-nums">
              {now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
            </p>
            <p className="text-sm text-emerald-300">
              {now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
            </p>
          </div>
        </div>
      </header>

      {/* Body */}
      <main className="flex-1 flex items-start justify-center px-6 py-8 overflow-y-auto">
        {showActiveOrder ? (
          /* Active order receipt */
          <div className="w-full max-w-5xl">
            <div className="bg-white/5 border border-white/10 rounded-2xl overflow-hidden shadow-2xl">
              <div className="bg-emerald-600/20 border-b border-white/10 px-6 py-4 text-center">
                <p className="text-xs font-bold uppercase tracking-widest text-emerald-300 mb-1">Current Order</p>
                <p className="text-sm text-slate-400">{cart.length} item type{cart.length !== 1 ? 's' : ''}</p>
                <p className="text-sm text-emerald-200 mt-1">Payment method: {activePaymentMethod}</p>
                <p className="text-sm text-emerald-200">Customer: {activeCustomerName}</p>
              </div>

              <div className="grid grid-cols-3 gap-6 p-6">
                {/* Left column: items list */}
                <div className="col-span-2 divide-y divide-white/5 max-h-[55vh] overflow-y-auto rounded-lg border border-white/5 bg-black/20">
                  <div className="flex items-center gap-3 px-4 py-2 bg-white/5 text-xs font-bold uppercase tracking-wider text-slate-400 sticky top-0 z-10">
                    <span className="flex-1">Item</span>
                    <span className="w-12 text-center">Qty</span>
                    <span className="w-20 text-center">Price</span>
                    <span className="w-24 text-right">Amount</span>
                  </div>

                  {cart.map((item, index) => {
                    const price = Number(item?.sellingPrice ?? item?.price ?? 0);
                    const qty = Number(item.qty) || 0;
                    const lineTotal = price * qty;
                    return (
                      <div
                        key={item.productId}
                        className={`flex items-center gap-3 px-4 py-4 transition-all ${index === cart.length - 1 ? 'bg-emerald-500/10' : ''}`}
                      >
                        <span className="w-5 text-xs text-slate-500 shrink-0">{index + 1}.</span>
                        <span className="flex-1 text-base font-semibold text-white leading-tight line-clamp-2">
                          {item.productName || 'Item'}
                        </span>
                        <span className="w-12 text-center text-sm font-bold text-emerald-300 tabular-nums shrink-0">
                          × {qty}
                        </span>
                        <span className="w-20 text-center text-sm text-slate-400 tabular-nums shrink-0">
                          {formatCurrency(price)}
                        </span>
                        <span className="w-24 text-right text-base font-bold text-white tabular-nums shrink-0">
                          {formatCurrency(lineTotal)}
                        </span>
                      </div>
                    );
                  })}
                </div>

                {/* Right column: totals and QR */}
                <div className="col-span-1 flex flex-col gap-6">
                  {/* Totals section */}
                  <div className="border border-white/10 rounded-lg bg-black/30 p-5 space-y-3">
                    <div className="flex justify-between text-sm text-slate-300">
                      <span>Subtotal</span>
                      <span className="tabular-nums font-semibold">{formatCurrency(subtotal)}</span>
                    </div>

                    {discountAmount > 0 && (
                      <div className="flex justify-between text-sm text-emerald-300 pb-2 border-b border-white/10">
                        <span>
                          Discount
                          {appliedDiscount ? ` (${appliedDiscount.label})` : ''}
                        </span>
                        <span className="tabular-nums font-semibold">- {formatCurrency(discountAmount)}</span>
                      </div>
                    )}

                    <div className="flex justify-between items-center pt-2">
                      <span className="text-lg font-black text-white">TOTAL</span>
                      <span className="text-2xl font-black text-emerald-400 tabular-nums">{formatCurrency(grandTotal)}</span>
                    </div>
                  </div>

                  {/* ABA QR section */}
                  {isActiveAbaPayment && (
                    <div className="border border-white/10 rounded-lg bg-slate-900/40 p-5 flex flex-col items-center">
                      <p className="text-xs font-bold uppercase tracking-widest text-sky-200 mb-3">Scan ABA QR</p>
                      {!abaQrLoadError ? (
                        <img
                          src={abaQrImageSrc}
                          alt="ABA QR Payment"
                          className="h-48 w-48 rounded-lg border border-white/20 bg-white object-cover p-1"
                          onError={handleAbaQrImageError}
                        />
                      ) : (
                        <div className="rounded-lg border border-amber-300/30 bg-amber-500/10 px-3 py-2 text-center text-xs text-amber-100">
                          ABA QR image not found. Add aba-qr.png/jpg to /images
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            </div>

            <p className="text-center text-sm text-slate-500 mt-5">Please proceed to payment</p>
          </div>
        ) : showCompletedSale ? (
          /* Payment completed receipt */
          <div className="w-full max-w-5xl">
            <div className="bg-emerald-500/10 border border-emerald-300/30 rounded-2xl overflow-hidden shadow-2xl">
              <div className="bg-emerald-500/20 border-b border-emerald-200/20 px-6 py-4 text-center">
                <p className="text-sm font-black uppercase tracking-widest text-emerald-200">Payment Completed</p>
                <p className="text-lg font-bold text-white mt-1">Method: {completedPaymentMethod}</p>
                <p className="text-sm text-emerald-100 mt-1">Customer: {completedCustomerName}</p>
              </div>

              <div className="grid grid-cols-3 gap-6 p-6">
                {/* Left column: completed items */}
                <div className="col-span-2 divide-y divide-white/5 max-h-[42vh] overflow-y-auto rounded-lg border border-white/5 bg-black/20">
                  {completedCart.map((item) => {
                    const price = Number(item?.sellingPrice ?? item?.price ?? 0);
                    const qty = Number(item.qty) || 0;
                    const lineTotal = price * qty;
                    return (
                      <div key={`done-${item.productId}`} className="flex items-center gap-3 px-4 py-3">
                        <span className="flex-1 text-sm font-semibold text-white line-clamp-1">{item.productName || 'Item'}</span>
                        <span className="w-16 text-center text-xs font-bold text-emerald-200 tabular-nums">x {qty}</span>
                        <span className="w-24 text-right text-sm font-bold text-white tabular-nums">{formatCurrency(lineTotal)}</span>
                      </div>
                    );
                  })}
                </div>

                {/* Right column: totals and ABA confirmation */}
                <div className="col-span-1 flex flex-col gap-6">
                  {/* Totals section */}
                  <div className="border border-emerald-200/20 rounded-lg bg-black/30 p-5 space-y-3">
                    <div className="flex justify-between text-sm text-emerald-100">
                      <span>Subtotal</span>
                      <span className="tabular-nums font-semibold">{formatCurrency(completedSubtotal)}</span>
                    </div>
                    {completedDiscountAmount > 0 && (
                      <div className="flex justify-between text-sm text-emerald-100 pb-2 border-b border-emerald-200/20">
                        <span>
                          Discount
                          {completedAppliedDiscount ? ` (${completedAppliedDiscount.label})` : ''}
                        </span>
                        <span className="tabular-nums font-semibold">- {formatCurrency(completedDiscountAmount)}</span>
                      </div>
                    )}
                    <div className="flex justify-between items-center pt-2">
                      <span className="text-lg font-black text-white">PAID</span>
                      <span className="text-2xl font-black text-emerald-300 tabular-nums">{formatCurrency(completedGrandTotal)}</span>
                    </div>
                  </div>

                  {/* ABA confirmation section */}
                  {isAbaPayment && (
                    <div className="border border-sky-200/40 rounded-lg bg-sky-500/10 p-5 flex flex-col items-center">
                      <div className="inline-flex items-center gap-2 rounded-full border border-sky-200/40 bg-sky-500/20 px-3 py-1.5 text-xs font-black uppercase tracking-wider text-sky-100 mb-3">
                        <span className="inline-flex h-4 w-4 items-center justify-center rounded-full bg-sky-300/30 text-[9px]">A</span>
                        ABA Confirmed
                      </div>
                      {!abaQrLoadError ? (
                        <img
                          src={abaQrImageSrc}
                          alt="ABA QR Payment"
                          className="h-32 w-32 rounded-lg border border-white/20 bg-white object-cover p-1"
                          onError={handleAbaQrImageError}
                        />
                      ) : (
                        <p className="text-xs text-amber-100">ABA QR image not found</p>
                      )}
                    </div>
                  )}
                </div>
              </div>
            </div>

            <p className="text-center text-sm text-emerald-200 mt-5">{thankYouMessage}</p>
          </div>
        ) : (
          /* Idle screen */
          <div className="flex flex-col items-center justify-center text-center mt-24">
            <div className="w-24 h-24 rounded-full bg-emerald-500/20 flex items-center justify-center mb-6">
              <svg className="w-12 h-12 text-emerald-400" fill="none" stroke="currentColor" strokeWidth="1.5" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 10.5V6a3.75 3.75 0 1 0-7.5 0v4.5m11.356-1.993 1.263 12c.07.665-.45 1.243-1.119 1.243H4.25a1.125 1.125 0 0 1-1.12-1.243l1.264-12A1.125 1.125 0 0 1 5.513 7.5h12.974c.576 0 1.059.435 1.119 1.007Z" />
              </svg>
            </div>
            <h2 className="text-4xl font-black text-white mb-3">Welcome!</h2>
            <p className="text-xl text-emerald-200">Waiting for your order...</p>
            <p className="text-sm text-slate-400 mt-4">Your items will appear here when scanned</p>
          </div>
        )}
      </main>
    </div>
  );
};

export default CustomerDisplay;
